async function submitFinanceCaptureInput(sourceInput = null) {
  const input = sourceInput || document.getElementById('finance-capture-input') || document.getElementById('mobile-detail-input');
  if (!input) return false;
  const text = String(input.value || '').trim();
  if (!text) return false;
  const action = extractExpenseRecordFromQuestion(text);
  if (!action) {
    setFinanceHostFeedback('还没识别出完整账目信息，试试“咖啡 28”或“房租 3200”', 'error');
    return false;
  }
  const ledger = ensureExpenseLedgerShape(data);
  const beforeLedger = cloneJSONSafe(ledger, { categories: [], records: [] }) || { categories: [], records: [] };
  const restoreLedger = () => {
    if (!ledger || typeof ledger !== 'object') return;
    ledger.categories = Array.isArray(beforeLedger.categories) ? beforeLedger.categories.slice() : [];
    ledger.records = Array.isArray(beforeLedger.records) ? beforeLedger.records.slice() : [];
  };
  const record = normalizeExpenseLedgerRecord({
    id: genId(),
    item: String(action.item || '').trim(),
    category: normalizeExpenseLedgerCategory(String(action.category || '').trim(), text),
    amount: Number(action.amount),
    note: String(action.note || '').trim(),
    spentAt: String(action.spentAt || '').trim() || formatDateTimeFull(new Date()).slice(0, 16),
    createdAt: new Date().toISOString(),
    source: 'finance-host',
  });
  if (!record) {
    setFinanceHostFeedback('这条内容没能整理成有效账目，请再补一下金额或项目名。', 'error');
    return false;
  }
  const dedupKey = buildExpenseLedgerDedupKey(record);
  const duplicate = (Array.isArray(ledger.records) ? ledger.records : []).some((item) => buildExpenseLedgerDedupKey(item) === dedupKey);
  if (duplicate) {
    setFinanceHostFeedback('这笔账已经在账本里了，我帮你自动去重了。', 'success');
    if (input.id === 'mobile-detail-input') resetComposerInput(input, { syncMobileLayout: true });
    else resetComposerInput(input);
    return true;
  }
  if (typeof commitMorphCoreMutation !== 'function') {
    setFinanceHostFeedback('这次记账没有拿到统一提交通道，已阻止写入，请稍后重试。', 'error');
    return false;
  }
  if (!ledger.categories.includes(record.category)) ledger.categories.push(record.category);
  ledger.records.unshift(record);
  const committed = commitMorphCoreMutation({
    changed: true,
    source: 'manual',
    promptQuestion: `手动快速记账：${String(record.item || '').trim()}`,
    actions: [{ type: 'manual_create_expense_record', entityId: String(record.id || '').trim(), item: record.item, amount: record.amount, category: record.category }],
    actionTypes: ['manual_create_expense_record'],
    domains: ['expenseLedger'],
    beforeDomains: { expenseLedger: beforeLedger },
    appliedLabels: [`手动快速记账：${String(record.item || '').trim()}`],
    detail: { entityId: String(record.id || '').trim(), item: record.item, amount: record.amount, category: record.category },
    entityRefs: [{ domain: 'expenseLedger', entityType: 'expense_record', entityId: String(record.id || '').trim(), action: 'create', label: String(record.item || '').trim() }],
    saveMode: 'data',
    immediatePersist: true,
    recordMorphActionTransaction,
    protectRecentCommittedData,
    setLastUserEditAt: (value) => { lastUserEditAt = Number.isFinite(Number(value)) ? Number(value) : lastUserEditAt; },
    bumpUISessionLock,
    saveData,
    currentTab,
    skipRender: currentTab === 'ai',
  });
  if (!committed) {
    restoreLedger();
    setFinanceHostFeedback('这次记账没有成功提交到 MorphCore，请重试。', 'error');
    return false;
  }
  syncExpenseLedgerExtensionFiles(record);
  if (input.id === 'mobile-detail-input') {
    resetComposerInput(input, { syncMobileLayout: true });
    mobileFinanceAIComposeActive = false;
    syncMobileBottomNavState();
    syncMobileQuickComposeButton();
  } else {
    resetComposerInput(input, { keepFocus: true });
  }
  setFinanceHostFeedback(`已记账：${buildExpenseLedgerSummary(record)}`, 'success');
  if (currentTab === 'finance') renderFinanceHostView();
  return true;
}
