  if (!host || !bar) return;
  const visible = isThoughtGraphInteractive() && host.dataset.orbLayout === 'graph';
  host.classList.toggle('thought-graph-shortcuts-active', thoughtGraphShortcutActive === true);
  bar.classList.toggle('hidden', !visible);
  const badgeEl = document.getElementById('thought-graph-status-badge');
  const titleEl = document.getElementById('thought-graph-status-title');
  const iconEl = bar.querySelector('.thought-graph-status-icon');
