function getThoughtGraphAveragePoint(entries = []) {
  const list = Array.isArray(entries) ? entries.filter((entry) => entry?.point) : [];
  if (!list.length) return null;
  const totals = list.reduce((acc, entry) => ({
    x: acc.x + Number(entry.point.x || 0),
    y: acc.y + Number(entry.point.y || 0),
  }), { x: 0, y: 0 });
  return {
    x: totals.x / list.length,
    y: totals.y / list.length,
  };
}
function chooseThoughtGraphSpatialNextItem(kind = '', items = [], currentId = '', options = {}) {
  const normalizedKind = String(kind || '').trim();
  const normalizedCurrentId = String(currentId || '').trim();
  const list = Array.isArray(items) ? items.filter(Boolean) : [];
  if (!normalizedKind || !normalizedCurrentId || list.length < 2) return null;
  const currentMeta = getThoughtGraphNodeNavigationMeta(normalizedKind, normalizedCurrentId);
  const currentPoint = currentMeta?.point || null;
  if (!currentPoint) return null;
  const visitedIds = Array.isArray(options.visitedIds) ? options.visitedIds.map((id) => String(id || '').trim()).filter(Boolean) : [];
  const visitedSet = new Set(visitedIds);
  const candidates = list.map((item) => {
    const itemId = String(item?.id || '').trim();
    const meta = getThoughtGraphNodeNavigationMeta(normalizedKind, itemId);
    const point = meta?.point || null;
    if (!itemId || !point || itemId === normalizedCurrentId) return null;
    const dx = Number(point.x || 0) - Number(currentPoint.x || 0);
    const dy = Number(point.y || 0) - Number(currentPoint.y || 0);
    return {
      item,
      itemId,
      point,
      groupKey: String(meta?.groupKey || '').trim(),
      adjacentGroupKeys: Array.isArray(meta?.adjacentGroupKeys) ? meta.adjacentGroupKeys.map((key) => String(key || '').trim()).filter(Boolean) : [],
      distance: Math.hypot(dx, dy),
      axisPenalty: Math.abs(dy) * 0.08,
    };
  }).filter(Boolean);
  const pool = candidates.filter((entry) => !visitedSet.has(entry.itemId));
  if (!pool.length) return null;
  const sortEntriesBySpatialDistance = (entries = []) => [...entries].sort((a, b) => {
    if (Math.abs(a.distance - b.distance) > 0.5) return a.distance - b.distance;
    if (Math.abs(a.axisPenalty - b.axisPenalty) > 0.1) return a.axisPenalty - b.axisPenalty;
    if (Math.abs(Number(a.point.y || 0) - Number(b.point.y || 0)) > 1) return Number(a.point.y || 0) - Number(b.point.y || 0);
    return Number(a.point.x || 0) - Number(b.point.x || 0);
  });
  const currentGroupKey = String(currentMeta?.groupKey || '').trim();
  if (!currentGroupKey) return sortEntriesBySpatialDistance(pool)[0]?.item || null;
  const sameGroupPool = pool.filter((entry) => entry.groupKey === currentGroupKey);
  if (sameGroupPool.length) return sortEntriesBySpatialDistance(sameGroupPool)[0]?.item || null;
  const currentGroupEntries = candidates.filter((entry) => entry.groupKey === currentGroupKey);
  const currentGroupCenter = getThoughtGraphAveragePoint(currentGroupEntries) || currentPoint;
  const currentAdjacentGroupKeys = new Set(Array.isArray(currentMeta?.adjacentGroupKeys) ? currentMeta.adjacentGroupKeys.map((key) => String(key || '').trim()).filter(Boolean) : []);
  const groups = new Map();
  pool.forEach((entry) => {
    const groupKey = String(entry.groupKey || '').trim();
    const bucketKey = groupKey || `__solo__:${entry.itemId}`;
    const bucket = groups.get(bucketKey) || {
      bucketKey,
      groupKey,
      entries: [],
    };
    bucket.entries.push(entry);
    groups.set(bucketKey, bucket);
  });
  const rankedGroups = Array.from(groups.values()).map((group) => {
    const center = getThoughtGraphAveragePoint(group.entries) || group.entries[0]?.point || currentPoint;
    const dx = Number(center?.x || 0) - Number(currentGroupCenter.x || 0);
    const dy = Number(center?.y || 0) - Number(currentGroupCenter.y || 0);
    const centerDistance = Math.hypot(dx, dy);
    return {
      ...group,
      adjacencyRank: group.groupKey && currentAdjacentGroupKeys.has(group.groupKey) ? 0 : 1,
      hasGroupKey: !!group.groupKey,
      centerDistance,
      nearestEntryDistance: Math.min(...group.entries.map((entry) => Number(entry.distance || 0))),
    };
  });
  rankedGroups.sort((a, b) => {
    if (a.adjacencyRank !== b.adjacencyRank) return a.adjacencyRank - b.adjacencyRank;
    if (a.hasGroupKey !== b.hasGroupKey) return a.hasGroupKey ? -1 : 1;
    if (Math.abs(a.centerDistance - b.centerDistance) > 0.5) return a.centerDistance - b.centerDistance;
    if (Math.abs(a.nearestEntryDistance - b.nearestEntryDistance) > 0.5) return a.nearestEntryDistance - b.nearestEntryDistance;
    return String(a.bucketKey || '').localeCompare(String(b.bucketKey || ''));
  });
  const nextGroup = rankedGroups[0] || null;
  if (!nextGroup?.entries?.length) return sortEntriesBySpatialDistance(pool)[0]?.item || null;
  return sortEntriesBySpatialDistance(nextGroup.entries)[0]?.item || null;
}
function getThoughtGraphKeyboardPreviewDescriptor() {
  const mode = String(thoughtGraphKeyboardNavigation.mode || '').trim();
  if (mode === 'fixed') {
    const fixedThoughtId = String(thoughtGraphKeyboardNavigation.fixedThoughtId || '').trim();
    const item = fixedThoughtId ? findActiveThoughtByRef('fixed', fixedThoughtId) : null;
    if (!item) return null;
    return { kind: 'fixed', id: fixedThoughtId, item };
  }
  if (mode === 'flash') {
    const flashThoughtId = String(thoughtGraphKeyboardNavigation.flashThoughtId || '').trim();
    const item = flashThoughtId ? findActiveThoughtByRef('flashThoughts', flashThoughtId) : null;
    if (!item) return null;
    return { kind: 'flashThoughts', id: flashThoughtId, item };
  }
  return null;
}
function resolveThoughtGraphKeyboardPreviewResumeItem() {
  const mode = String(thoughtGraphKeyboardNavigation.mode || '').trim();
  if (mode !== 'flash' && mode !== 'fixed') return null;
  const kind = mode === 'fixed' ? 'fixed' : 'flashThoughts';
  const items = mode === 'fixed' ? getThoughtGraphFixedNavigationItems() : getThoughtGraphFlashNavigationItems();
  if (!items.length) return null;
  const currentId = String(mode === 'fixed' ? thoughtGraphKeyboardNavigation.fixedThoughtId || '' : thoughtGraphKeyboardNavigation.flashThoughtId || '').trim();
  const currentItem = currentId ? items.find((item) => String(item?.id || '').trim() === currentId) : null;
  if (currentItem) return { kind, item: currentItem };
  const visitedIds = normalizeThoughtGraphVisitedIds(kind, items);
  const nextUnread = items.find((item) => !visitedIds.includes(String(item?.id || '').trim()));
  return { kind, item: nextUnread || items[0] };
}
function isThoughtGraphKeyboardPreviewActive() {
  if (!isThoughtGraphInteractive()) return false;
  return !!getThoughtGraphKeyboardPreviewDescriptor();
}
