function syncAIInputLoadingState() {
  const resolvedInputContext = currentTab === 'ai'
    ? resolveAIChatSendInputContext()
    : { input: getAIChatInputElement(), question: '' };
  const input = resolvedInputContext.input || getAIChatInputElement();

  const shouldRestoreAIPlaceholder = !!(input && currentTab === 'ai');
  if (shouldRestoreAIPlaceholder) {
    if (!input.dataset.aiBasePlaceholder) {
      input.dataset.aiBasePlaceholder = input.getAttribute('placeholder') || '输入内容... (Enter 发送，Cmd/Ctrl+Enter 换行)';
    }
    input.placeholder = input.dataset.aiBasePlaceholder;
    input.disabled = false;
  }

  const submitBtn = document.getElementById('omni-submit-btn');
  const submitIcon = submitBtn?.querySelector('i');
  if (submitBtn && submitIcon) {
    const hasText = currentTab === 'ai'
      ? !!String(resolvedInputContext.question || '').trim()
      : !!String(input?.value || '').trim();
    const iconName = currentTab === 'ai'
      ? (aiChatState.busy ? 'loader-2' : 'arrow-up')
      : currentTab === 'flashThoughts'
        ? 'arrow-up'
        : 'send';
    submitIcon.setAttribute('data-lucide', iconName);
    submitIcon.classList.remove('animate-spin');
    if (currentTab === 'ai' && aiChatState.busy) submitIcon.classList.add('animate-spin');
    const label = currentTab === 'ai' && !hasText ? '输入内容后发送' : '发送';
    submitBtn.setAttribute('aria-label', label);
    requestLucideRefresh({ root: submitBtn });
  }
  const syncComposerActionButton = (button, visible, options = {}) => {
    if (!button) return;
    const disabled = options.disabled === true;
    const display = options.display || 'flex';
    button.classList.toggle('hidden', !visible);
    button.classList.toggle('flex', visible);
    button.style.display = visible ? display : 'none';
    button.disabled = disabled;
    if (options.ariaLabel) button.setAttribute('aria-label', options.ariaLabel);
    requestLucideRefresh({ root: button });
  };

  const aiChatSendBtn = document.getElementById('ai-chat-send-btn');
  const aiChatStopBtn = document.getElementById('ai-chat-stop-btn');
  const aiChatDrawerSendBtn = document.getElementById('ai-chat-drawer-send-btn');
  const aiChatDrawerStopBtn = document.getElementById('ai-chat-drawer-stop-btn');

  syncComposerActionButton(aiChatSendBtn, !aiChatState.busy, {
    disabled: !!aiChatState.busy,
  });
  syncComposerActionButton(aiChatStopBtn, !!aiChatState.busy, {
    disabled: !aiChatState.busy,
    ariaLabel: aiChatState.busy ? '停止生成' : '停止',
  });
  syncComposerActionButton(aiChatDrawerSendBtn, !aiChatState.busy, {
    disabled: !!aiChatState.busy,
  });
  syncComposerActionButton(aiChatDrawerStopBtn, !!aiChatState.busy, {
    disabled: !aiChatState.busy,
    ariaLabel: aiChatState.busy ? '停止生成' : '停止',
  });

  const aiPlusBtn = document.getElementById('omni-ai-plus-btn');
  if (aiPlusBtn) {
    const showPlus = AI_COMPOSER_PLUS_ENABLED && currentTab === 'ai' && !isMobileNavMode();
    aiPlusBtn.classList.toggle('hidden', !showPlus);
    aiPlusBtn.style.display = showPlus ? 'flex' : 'none';
    aiPlusBtn.disabled = !!aiChatState.busy;
  }
  renderAIInlineUploadIntent();
  renderAIPendingTimeBlockIntent();
  renderAIPendingWebSearchIntent();
  renderAIPendingUtilityCategoryIntent();
  syncThoughtsComposerChrome(currentTab);
  if (isMobileNavMode()) syncMobileContextDetailInputState();
}
