function buildDefaultAIUserMarkdown() { return [ '# user.md', '', '用户偏好把长期思考沉淀为系统，并希望 AI 既能讨论，也能执行。', '', '- 偏好连续、稳定、低中断的交互', '- 经常围绕写作、工具、时间、数字生活、人文与长期项目展开', '- 希望 AI 对历史上下文有持续记忆，而不是每次从零开始', '', '## 名字与称呼', '', '（如果用户明确说了自己的名字、昵称或希望被怎样称呼，要稳定写在这里，并在后续优先沿用最新版本。）', '', '## 归类与整理偏好', '', '（你手动拖拽闪念到项目、移回闪念、分组等行为会被记录；AI 会结合这些记录与整理/去重时的选择，归纳并写入此处，下次帮你整理时优先参考。）', '', '## 日志记录偏好', '', '- 当用户已经写出较完整的原句、段落、节奏或思考细节时，优先保留原有写法，只做必要清理，不要擅自整理成另一种口吻。', '- 当用户明确要求“整理 / 归纳 / 改写 / 生成一版日志”时，再主动重组结构与措辞，产出更成型的日志版本。', '- 若用户只是说“放进日志”且同时给了现成内容，默认更偏向保留原味；若用户是让 AI 根据上下文生成日志，默认更偏向整理成文。', '', '## 回答表达偏好', '', '- 默认像正常人聊天一样一段一段说，少用项目符号和列表。', '- 除非内容本身天然就是步骤、选项、清单或明确对比，否则不要把回答拆成 bullet point。', '- 如果确实要用 1、2、3，每一项也应该是有内容的小段，不要写成很碎的提纲。', '', ].join('\n'); }
