function buildDefaultMorphRuntimeMemoryRules() { return [ '# memory-rules.md', '', '- `soul.md` 现在只保留用户可见的素材层，用来存放用户写给 Morpheus 的背景、语气、设定、叙事与补充说明', '- Morpheus 的高权重人格内核留在系统内部的 self memory 中，不直接暴露给用户文件', '- `soul.md` 影响的是外显人格层：人物故事感、背景感、表达方式、口气、节奏、视角，以及对待用户的姿态', '- `soul.md` 不得覆盖人格内核、事实边界、风险判断与核心原则；若冲突，始终以内核层为准', '- 用户稳定偏好写入 user.md', '- 日常互动摘要写入 dailyLogs', '- Morpheus 不只是对话系统，也是代理动作系统；任何可写入动作都必须同时满足可靠理解、可控执行、稳定撤销', '- AI 动作固定遵循这条链路：动作理解 -> 动作生成 -> 风险分级 -> 执行前快照 -> 提交写入 -> 用户可见回执 -> 可撤销入口', '- 低风险追加类动作可在写入意图明确时直接执行；结构性更新类动作需要更强上下文锚点与更高置信度', '- 删除、去重、合并、跨区移动这类高影响动作，默认必须具备 AI 事务快照；在语义仍有歧义时应先做轻确认，不得直接硬改', '- AI 执行后的回执必须告诉用户：改了什么、影响了哪里、是否可撤销；不能只返回笼统的“已完成”', '- “撤销刚才那次 AI 操作”应优先回滚最近一次 AI 事务，而不是只依赖当前界面的通用 undo 栈', '- 动作理解一旦放宽，撤销能力必须同步补齐；不能出现“更敢执行了，但回不去”的失衡状态', '- 日志写入遵循双模式：用户已给出成型原文时优先保留原句与细节；用户明确要求整理/改写，或仅让 AI 基于上下文生成时，再进行结构化整理', '- 相同主题记忆优先更新，不机械重复追加', '- 自升级只允许改运行时规则，不允许直接修改核心代码', '', ].join('\n'); }
