function addItemFromDetailComposer() {
  const mode = currentDetailMeta?.mode || '';
  if (!mode.startsWith('create-')) return false;
  const editor = document.getElementById('detail-editor-rich');
  if (!editor) return false;
  const text = extractPlainTextFromRich(editor).trim();
  const html = editor.innerHTML || '';
  if (!text && !html.replace(/<br\s*\/?>/gi, '').trim()) return false;
  const now = new Date();
  const item = {
    id: genId(),
    text,
    html,
    time: `${String(now.getHours()).padStart(2,'0')}:${String(now.getMinutes()).padStart(2,'0')}`,
    createdAt: now.toISOString(),
  };
  if (mode === 'create-flashThoughts') {
    const changed = performMorphTransactionalMutation({
      source: 'manual',
      actionType: 'manual_add_flash_thought_from_detail',
      promptQuestion: `手动新增闪念：${text.slice(0, 16)}`,
      domains: ['thoughts'],
      detail: {
        entityId: String(item.id || '').trim(),
        text: text.slice(0, 120),
      },
      mutation: () => {
        data.flashThoughts.push(item);
        return {
          changed: true,
          appliedLabel: `手动新增闪念：${text.slice(0, 16)}`,
          createdItems: [{ tab: 'flashThoughts', id: String(item.id || '').trim(), text: item.text || text }],
        };
      },
    });
    if (!changed) return false;
    closeDetailModal();
    return true;
  } else if (mode === 'create-fixed') {
    const changed = performMorphTransactionalMutation({
      source: 'manual',
      actionType: 'manual_add_fixed_thought_from_detail',
      promptQuestion: `手动新增定念：${text.slice(0, 16)}`,
      domains: ['thoughts'],
      detail: {
        entityId: String(item.id || '').trim(),
        text: text.slice(0, 120),
      },
      mutation: () => {
        data.fixed.push(item);
        return {
          changed: true,
          appliedLabel: `手动新增定念：${text.slice(0, 16)}`,
          createdItems: [{ tab: 'fixed', id: String(item.id || '').trim(), text: item.text || text }],
        };
      },
    });
    if (!changed) return false;
    closeDetailModal();
    return true;
  } else if (mode === 'create-daily') {
    const monthKey = currentTab === 'daily' ? ensureSelectedDailyMonth() : getMonthStr();
    const line = item.time ? `${item.time} ${text}`.trim() : text;
    const block = { id: genId(), type: 'p', content: line, checked: false };
    if (html && html.trim()) block.html = html;
    const changed = performMorphTransactionalMutation({
      source: 'manual',
      actionType: 'manual_add_daily_block_from_detail',
      promptQuestion: `手动新增日志：${text.slice(0, 16)}`,
      domains: ['daily'],
      detail: {
        monthKey: String(monthKey || '').trim(),
        blockId: String(block.id || '').trim(),
        text: text.slice(0, 120),
      },
      mutation: () => {
        if (!data.dailyMonths[monthKey]) data.dailyMonths[monthKey] = [];
        data.dailyMonths[monthKey].push(block);
        return {
          changed: true,
          appliedLabel: `手动新增日志：${text.slice(0, 16)}`,
          createdItems: [{ tab: 'daily', id: String(block.id || '').trim(), text: line, monthKey: String(monthKey || '').trim() }],
        };
      },
    });
    if (!changed) return false;
    closeDetailModal();
    return true;
  } else if (mode === 'create-project') {
    const ctxType = mode.replace('create-', '');
    if (!activeContextId) {
      openCustomModal({ title: '请先进入详情', desc: '先打开一个具体条目，再添加内容。' });
      return false;
    }
    const ctx = data[`${ctxType}s`].find(x => x.id === activeContextId);
    if (!ctx) return false;
    const changed = performMorphTransactionalMutation({
      source: 'manual',
      actionType: 'manual_add_project_reference_from_detail',
      promptQuestion: `手动新增项目条目：${text.slice(0, 16)}`,
      domains: ['projects'],
      detail: {
        entityId: String(item.id || '').trim(),
        projectId: String(ctx.id || '').trim(),
        text: text.slice(0, 120),
      },
      mutation: () => {
        if (!ctx.items) ctx.items = [];
        ctx.items.unshift(item);
        return {
          changed: true,
          appliedLabel: `手动新增项目条目：${text.slice(0, 16)}`,
          createdItems: [{ tab: 'project', id: String(item.id || '').trim(), text: item.text || text, projectId: String(ctx.id || '').trim() }],
        };
      },
    });
    if (!changed) return false;
    closeDetailModal();
    return true;
  } else {
    return false;
  }
}
