  menu.dataset.rhythmKind = normalizedKind;
  menu.hidden = false;
  menu.setAttribute('aria-hidden', 'false');
  const rect = event?.currentTarget?.getBoundingClientRect?.() || { left: 0, bottom: 0 };
  const width = 128;
  const left = Math.max(8, Math.min((window.innerWidth || 0) - width - 8, Number(rect.left) || 8));
