  const next = sanitizeScheduleMvpState(state, { includeDefaults: false });
  const todayKey = getScheduleDayKey();
  next.customDone = next.customDone && typeof next.customDone === 'object' ? next.customDone : {};
  next.customDone[id] = next.customDone[id] && typeof next.customDone[id] === 'object' ? next.customDone[id] : {};
  next.customDoneAt = next.customDoneAt && typeof next.customDoneAt === 'object' ? next.customDoneAt : {};
  next.customDoneAt[id] = next.customDoneAt[id] && typeof next.customDoneAt[id] === 'object' ? next.customDoneAt[id] : {};
  if (done) {
    next.customDone[id][todayKey] = true;
    next.customDoneAt[id][todayKey] = next.customDoneAt[id][todayKey] || new Date().toISOString();
  } else {
    delete next.customDone[id][todayKey];
    delete next.customDoneAt[id][todayKey];
  }
  writeScheduleMvpState(next);
  renderScheduleView();
  const rhythm = findCustomScheduleRhythm(next, id);
  showScheduleFeedbackToast(done ? '已记录节律' : '已撤销今日记录', rhythm?.title || '自定义节律', done ? 'check' : 'rotate-ccw');
