  const frequency = normalizeScheduleRhythmFrequency(source.frequency, inferScheduleRhythmFrequencyFromCadence(source.cadence || '每天'));
  const target = normalizeScheduleRhythmTargetCount(source.targetCount, 1);
  const doneMap = id && state.customDone && typeof state.customDone === 'object' && state.customDone[id] && typeof state.customDone[id] === 'object'
