function inferListStyleFromText(text = '') {
  const clean = String(text || '').trim();
  if (!clean) return { type: 'p', content: '', checked: false };
  let match = clean.match(/^###\s+(.+)$/);
  if (match) return { type: 'h3', content: String(match[1] || '').trim(), checked: false };
  match = clean.match(/^##\s+(.+)$/);
  if (match) return { type: 'h2', content: String(match[1] || '').trim(), checked: false };
  match = clean.match(/^#\s+(.+)$/);
  if (match) return { type: 'h1', content: String(match[1] || '').trim(), checked: false };
  match = clean.match(/^>\s+(.+)$/);
  if (match) return { type: 'quote', content: String(match[1] || '').trim(), checked: false };
  if (/^(?:---|———|___)\s*$/.test(clean)) return { type: 'divider', content: '', checked: false };
  match = clean.match(/^[-*•]\s+\[([xX ])\]\s*(.+)$/);
  if (match) return { type: 'todo', content: String(match[2] || '').trim(), checked: String(match[1] || '').toLowerCase() === 'x' };
  match = clean.match(/^\[(?:([xX ])?)\]\s*(.+)$/);
  if (match) return { type: 'todo', content: String(match[2] || '').trim(), checked: String(match[1] || '').toLowerCase() === 'x' };
  match = clean.match(/^TODO[:：]?\s*(.+)$/i);
  if (match) return { type: 'todo', content: String(match[1] || '').trim(), checked: false };
  match = clean.match(/^DONE[:：]?\s*(.+)$/i);
  if (match) return { type: 'todo', content: String(match[1] || '').trim(), checked: true };
  match = clean.match(/^[-*•]\s+(.+)$/);
  if (match) return { type: 'bullet', content: String(match[1] || '').trim(), checked: false };
  match = clean.match(/^(\d+)[.)、]\s+(.+)$/);
  if (match) return { type: 'number', content: String(match[2] || '').trim(), checked: false };
  return { type: 'p', content: clean, checked: false };
}
